47	import org.springframework.boot.context.properties.source.ConfigurationPropertySources;
48	import org.springframework.boot.context.properties.source.UnboundElementsSourceFilter;
49	import org.springframework.context.ApplicationContext;
50	import org.springframework.context.ApplicationContextAware;
51	import org.springframework.context.ConfigurableApplicationContext;
52	import org.springframework.core.annotation.MergedAnnotations;
53	import org.springframework.core.convert.ConversionService;
54	import org.springframework.core.env.PropertySources;
55	import org.springframework.util.Assert;
56	import org.springframework.validation.Errors;
57	import org.springframework.validation.Validator;
58	import org.springframework.validation.annotation.Validated;
59	
60	/**
61	 * Internal class used by the {@link ConfigurationPropertiesBindingPostProcessor} to
62	 * handle the actual {@link ConfigurationProperties @ConfigurationProperties} binding.
63	 *
64	 * @author Stephane Nicoll
65	 * @author Phillip Webb
66	 */
67	class ConfigurationPropertiesBinder {
68	
69		private static final String BEAN_NAME = "org.springframework.boot.context.internalConfigurationPropertiesBinder";
70	
71		private static final String VALIDATOR_BEAN_NAME = EnableConfigurationProperties.VALIDATOR_BEAN_NAME;
72	
73		private final ApplicationContext applicationContext;
74	
75		private final PropertySources propertySources;
76	
77		private final @Nullable Validator configurationPropertiesValidator;
78	
79		private final boolean jsr303Present;
80	
81		private volatile @Nullable List<ConfigurationPropertiesBindHandlerAdvisor> bindHandlerAdvisors;
82	
83		private volatile @Nullable Binder binder;
84	
85		ConfigurationPropertiesBinder(ApplicationContext applicationContext) {
86			this.applicationContext = applicationContext;
87			this.propertySources = new PropertySourcesDeducer(applicationContext).getPropertySources();
88			this.configurationPropertiesValidator = getConfigurationPropertiesValidator(applicationContext);
89			this.jsr303Present = ConfigurationPropertiesJsr303Validator.isJsr303Present(applicationContext);
90		}
91	
92		BindResult<?> bind(ConfigurationPropertiesBean propertiesBean) {
93			Bindable<?> target = propertiesBean.asBindTarget();
94			ConfigurationProperties annotation = propertiesBean.getAnnotation();
95			BindHandler bindHandler = getBindHandler(target, annotation);
96			return getBinder().bind(annotation.prefix(), target, bindHandler);
97		}
98	
99		Object bindOrCreate(ConfigurationPropertiesBean propertiesBean) {
100			Bindable<?> target = propertiesBean.asBindTarget();
101			ConfigurationProperties annotation = propertiesBean.getAnnotation();
102			BindHandler bindHandler = getBindHandler(target, annotation);
103			return getBinder().bindOrCreate(annotation.prefix(), target, bindHandler);
104		}
105	
106		private @Nullable Validator getConfigurationPropertiesValidator(ApplicationContext applicationContext) {
107			if (applicationContext.containsBean(VALIDATOR_BEAN_NAME)) {
108				return applicationContext.getBean(VALIDATOR_BEAN_NAME, Validator.class);
109			}
110			return null;
111		}
112	
113		private <T> BindHandler getBindHandler(Bindable<T> target, ConfigurationProperties annotation) {
114			List<Validator> validators = getValidators(target);
115			BindHandler handler = getHandler();
116			handler = new ConfigurationPropertiesBindHandler(handler);
117			if (annotation.ignoreInvalidFields()) {
118				handler = new IgnoreErrorsBindHandler(handler);
119			}
120			if (!annotation.ignoreUnknownFields()) {
121				UnboundElementsSourceFilter filter = new UnboundElementsSourceFilter();
122				handler = new NoUnboundElementsBindHandler(handler, filter);
123			}
124			if (!validators.isEmpty()) {
125				handler = new ValidationBindHandler(handler, validators.toArray(new Validator[0]));
126			}
127			for (ConfigurationPropertiesBindHandlerAdvisor advisor : getBindHandlerAdvisors()) {
128				handler = advisor.apply(handler);
129			}
130			return handler;
131		}
132	
133		private List<ConfigurationPropertiesBindHandlerAdvisor> getBindHandlerAdvisors() {
134			List<ConfigurationPropertiesBindHandlerAdvisor> bindHandlerAdvisors = this.bindHandlerAdvisors;
135			if (bindHandlerAdvisors == null) {
136				bindHandlerAdvisors = this.applicationContext
137					.getBeanProvider(ConfigurationPropertiesBindHandlerAdvisor.class)
138					.orderedStream()
139					.toList();
140				this.bindHandlerAdvisors = bindHandlerAdvisors;
141			}
142			return bindHandlerAdvisors;
143		}
144	
145		private IgnoreTopLevelConverterNotFoundBindHandler getHandler() {
146			BoundConfigurationProperties bound = BoundConfigurationProperties.get(this.applicationContext);
147			return (bound != null)
148					? new IgnoreTopLevelConverterNotFoundBindHandler(new BoundPropertiesTrackingBindHandler(bound::add))
149					: new IgnoreTopLevelConverterNotFoundBindHandler();
150		}
151	
152		private List<Validator> getValidators(Bindable<?> target) {
153			List<Validator> validators = new ArrayList<>(3);
154			if (this.configurationPropertiesValidator != null) {
155				validators.add(this.configurationPropertiesValidator);
156			}
157			if (this.jsr303Present && target.getAnnotation(Validated.class) != null) {
158				Class<?> resolved = target.getType().resolve();
159				Assert.state(resolved != null, "'resolved' must not be null");
160				validators.add(getJsr303Validator(resolved));
161			}
162			Validator selfValidator = getSelfValidator(target);
163			if (selfValidator != null) {
164				validators.add(selfValidator);
165			}
166			return validators;
167		}
168	
169		private @Nullable Validator getSelfValidator(Bindable<?> target) {
170			if (target.getValue() != null) {
171				Object value = target.getValue().get();
172				return (value instanceof Validator validator) ? validator : null;
173			}
174			Class<?> type = target.getType().resolve();
175			if (type != null && Validator.class.isAssignableFrom(type)) {
176				return new SelfValidatingConstructorBoundBindableValidator(type);
177			}
178			return null;
179		}
180	
181		private Validator getJsr303Validator(Class<?> type) {
182			return new ConfigurationPropertiesJsr303Validator(this.applicationContext, type);
183		}
184	
185		private Binder getBinder() {
186			Binder binder = this.binder;
187			if (binder == null) {
188				binder = new Binder(getConfigurationPropertySources(), getPropertySourcesPlaceholdersResolver(),
189						getConversionServices(), getPropertyEditorInitializer(), null, null);
190				this.binder = binder;
191			}
192			return binder;
193		}
194	
195		private Iterable<ConfigurationPropertySource> getConfigurationPropertySources() {
196			return ConfigurationPropertySources.from(this.propertySources);
197		}
198	
199		private PropertySourcesPlaceholdersResolver getPropertySourcesPlaceholdersResolver() {
200			return new PropertySourcesPlaceholdersResolver(this.propertySources);
201		}
202	
203		private @Nullable List<ConversionService> getConversionServices() {
204			return new ConversionServiceDeducer(this.applicationContext).getConversionServices();
205		}
206	
207		private @Nullable Consumer<PropertyEditorRegistry> getPropertyEditorInitializer() {
208			if (this.applicationContext instanceof ConfigurableApplicationContext configurableContext) {
209				return configurableContext.getBeanFactory()::copyRegisteredEditorsTo;
210			}
211			return null;
212		}
213	
214		static void register(BeanDefinitionRegistry registry) {
215			if (!registry.containsBeanDefinition(BEAN_NAME)) {
216				BeanDefinition definition = BeanDefinitionBuilder
217					.rootBeanDefinition(ConfigurationPropertiesBinderFactory.class)
218					.getBeanDefinition();
219				definition.setRole(BeanDefinition.ROLE_INFRASTRUCTURE);
220				registry.registerBeanDefinition(BEAN_NAME, definition);
221			}
222		}
223	
224		static ConfigurationPropertiesBinder get(BeanFactory beanFactory) {
225			return beanFactory.getBean(BEAN_NAME, ConfigurationPropertiesBinder.class);
226		}
227	
228		/**
229		 * {@link BindHandler} to deal with
230		 * {@link ConfigurationProperties @ConfigurationProperties} concerns.
231		 */
232		private static class ConfigurationPropertiesBindHandler extends AbstractBindHandler {
233	
234			ConfigurationPropertiesBindHandler(BindHandler handler) {
235				super(handler);
236			}
237	
238			@Override
239			public <T> Bindable<T> onStart(ConfigurationPropertyName name, Bindable<T> target, BindContext context) {
240				return isConfigurationProperties(target.getType().resolve())
241						? target.withBindRestrictions(BindRestriction.NO_DIRECT_PROPERTY) : target;
242			}
243	
244			private boolean isConfigurationProperties(@Nullable Class<?> target) {
245				return target != null && MergedAnnotations.from(target).isPresent(ConfigurationProperties.class);
246			}
247	
248		}
249	
250		/**
251		 * {@link FactoryBean} to create the {@link ConfigurationPropertiesBinder}.
252		 */
253		static class ConfigurationPropertiesBinderFactory
254				implements FactoryBean<ConfigurationPropertiesBinder>, ApplicationContextAware {
255	
256			private @Nullable ConfigurationPropertiesBinder binder;
257	
258			@Override
259			public void setApplicationContext(ApplicationContext applicationContext) throws BeansException {
260				this.binder = (this.binder != null) ? this.binder : new ConfigurationPropertiesBinder(applicationContext);
261			}
262	
263			@Override
264			public Class<?> getObjectType() {
265				return ConfigurationPropertiesBinder.class;
266			}
267	
268			@Override
269			public ConfigurationPropertiesBinder getObject() throws Exception {
270				Assert.state(this.binder != null, "Binder was not created due to missing setApplicationContext call");
271				return this.binder;
272			}
273	
274		}
275	
276		/**
277		 * A {@code Validator} for a constructor-bound {@code Bindable} where the type being
278		 * bound is itself a {@code Validator} implementation.
279		 */
280		static class SelfValidatingConstructorBoundBindableValidator implements Validator {
281	
282			private final Class<?> type;
283	
284			SelfValidatingConstructorBoundBindableValidator(Class<?> type) {
285				this.type = type;
286			}
287	
288			@Override
289			public boolean supports(Class<?> candidate) {
290				return candidate.isAssignableFrom(this.type);
291			}
292	
293			@Override
294			public void validate(Object target, Errors errors) {
295				((Validator) target).validate(target, errors);
296			}
297	
298		}
299	
300	}
