17	package org.springframework.boot.context.properties.source;
18	
19	import java.util.Collections;
20	import java.util.stream.Stream;
21	
22	import org.jspecify.annotations.Nullable;
23	
24	import org.springframework.core.env.ConfigurableEnvironment;
25	import org.springframework.core.env.ConfigurablePropertyResolver;
26	import org.springframework.core.env.Environment;
27	import org.springframework.core.env.MutablePropertySources;
28	import org.springframework.core.env.PropertyResolver;
29	import org.springframework.core.env.PropertySource;
30	import org.springframework.core.env.PropertySource.StubPropertySource;
31	import org.springframework.core.env.PropertySources;
32	import org.springframework.core.env.PropertySourcesPropertyResolver;
33	import org.springframework.lang.Contract;
34	import org.springframework.util.Assert;
35	
36	/**
37	 * Provides access to {@link ConfigurationPropertySource ConfigurationPropertySources}.
38	 *
39	 * @author Phillip Webb
40	 * @since 2.0.0
41	 */
42	public final class ConfigurationPropertySources {
43	
44		/**
45		 * The name of the {@link PropertySource} {@link #attach(Environment) adapter}.
46		 */
47		private static final String ATTACHED_PROPERTY_SOURCE_NAME = "configurationProperties";
48	
49		private ConfigurationPropertySources() {
50		}
51	
52		/**
53		 * Create a new {@link PropertyResolver} that resolves property values against an
54		 * underlying set of {@link PropertySources}. Provides an
55		 * {@link ConfigurationPropertySource} aware and optimized alternative to
56		 * {@link PropertySourcesPropertyResolver}.
57		 * @param propertySources the set of {@link PropertySource} objects to use
58		 * @return a {@link ConfigurablePropertyResolver} implementation
59		 * @since 2.5.0
60		 */
61		public static ConfigurablePropertyResolver createPropertyResolver(MutablePropertySources propertySources) {
62			return new ConfigurationPropertySourcesPropertyResolver(propertySources);
63		}
64	
65		/**
66		 * Determines if the specific {@link PropertySource} is the
67		 * {@link ConfigurationPropertySource} that was {@link #attach(Environment) attached}
68		 * to the {@link Environment}.
69		 * @param propertySource the property source to test
70		 * @return {@code true} if this is the attached {@link ConfigurationPropertySource}
71		 */
72		public static boolean isAttachedConfigurationPropertySource(PropertySource<?> propertySource) {
73			return ATTACHED_PROPERTY_SOURCE_NAME.equals(propertySource.getName());
74		}
75	
76		/**
77		 * Attach a {@link ConfigurationPropertySource} support to the specified
78		 * {@link Environment}. Adapts each {@link PropertySource} managed by the environment
79		 * to a {@link ConfigurationPropertySource} and allows classic
80		 * {@link PropertySourcesPropertyResolver} calls to resolve using
81		 * {@link ConfigurationPropertyName configuration property names}.
82		 * <p>
83		 * The attached resolver will dynamically track any additions or removals from the
84		 * underlying {@link Environment} property sources.
85		 * @param environment the source environment (must be an instance of
86		 * {@link ConfigurableEnvironment})
87		 * @see #get(Environment)
88		 */
89		public static void attach(Environment environment) {
90			Assert.isInstanceOf(ConfigurableEnvironment.class, environment);
91			MutablePropertySources sources = ((ConfigurableEnvironment) environment).getPropertySources();
92			PropertySource<?> attached = getAttached(sources);
93			if (!isUsingSources(attached, sources)) {
94				attached = new ConfigurationPropertySourcesPropertySource(ATTACHED_PROPERTY_SOURCE_NAME,
95						new SpringConfigurationPropertySources(sources));
96			}
97			sources.remove(ATTACHED_PROPERTY_SOURCE_NAME);
98			sources.addFirst(attached);
99		}
100	
101		@Contract("null, _ -> false")
102		private static boolean isUsingSources(@Nullable PropertySource<?> attached, MutablePropertySources sources) {
103			return attached instanceof ConfigurationPropertySourcesPropertySource
104					&& ((SpringConfigurationPropertySources) attached.getSource()).isUsingSources(sources);
105		}
106	
107		static @Nullable PropertySource<?> getAttached(@Nullable MutablePropertySources sources) {
108			return (sources != null) ? sources.get(ATTACHED_PROPERTY_SOURCE_NAME) : null;
109		}
110	
111		/**
112		 * Return a set of {@link ConfigurationPropertySource} instances that have previously
113		 * been {@link #attach(Environment) attached} to the {@link Environment}.
114		 * @param environment the source environment (must be an instance of
115		 * {@link ConfigurableEnvironment})
116		 * @return an iterable set of configuration property sources
117		 * @throws IllegalStateException if not configuration property sources have been
118		 * attached
119		 */
120		public static Iterable<ConfigurationPropertySource> get(Environment environment) {
121			Assert.isInstanceOf(ConfigurableEnvironment.class, environment);
122			MutablePropertySources sources = ((ConfigurableEnvironment) environment).getPropertySources();
123			ConfigurationPropertySourcesPropertySource attached = (ConfigurationPropertySourcesPropertySource) sources
124				.get(ATTACHED_PROPERTY_SOURCE_NAME);
125			if (attached == null) {
126				return from(sources);
127			}
128			return attached.getSource();
129		}
130	
131		/**
132		 * Return {@link Iterable} containing a single new {@link ConfigurationPropertySource}
133		 * adapted from the given Spring {@link PropertySource}. The single element can be
134		 * {@code null} if the source cannot be adapted.
135		 * @param source the Spring property source to adapt
136		 * @return an {@link Iterable} containing a single newly adapted
137		 * {@link SpringConfigurationPropertySource}
138		 */
139		public static Iterable<@Nullable ConfigurationPropertySource> from(PropertySource<?> source) {
140			return Collections.singleton(ConfigurationPropertySource.from(source));
141		}
142	
143		/**
144		 * Return {@link Iterable} containing new {@link ConfigurationPropertySource}
145		 * instances adapted from the given Spring {@link PropertySource PropertySources}.
146		 * <p>
147		 * This method will flatten any nested property sources and will filter all
148		 * {@link StubPropertySource stub property sources}. Updates to the underlying source,
149		 * identified by changes in the sources returned by its iterator, will be
150		 * automatically tracked. The underlying source should be thread safe, for example a
151		 * {@link MutablePropertySources}
152		 * @param sources the Spring property sources to adapt
153		 * @return an {@link Iterable} containing newly adapted
154		 * {@link SpringConfigurationPropertySource} instances
155		 */
156		public static Iterable<ConfigurationPropertySource> from(Iterable<PropertySource<?>> sources) {
157			return new SpringConfigurationPropertySources(sources);
158		}
159	
160		private static Stream<PropertySource<?>> streamPropertySources(PropertySources sources) {
161			return sources.stream()
162				.flatMap(ConfigurationPropertySources::flatten)
163				.filter(ConfigurationPropertySources::isIncluded);
164		}
165	
166		private static Stream<PropertySource<?>> flatten(PropertySource<?> source) {
167			if (source.getSource() instanceof ConfigurableEnvironment configurableEnvironment) {
168				return streamPropertySources(configurableEnvironment.getPropertySources());
169			}
170			return Stream.of(source);
171		}
172	
173		private static boolean isIncluded(PropertySource<?> source) {
174			return !(source instanceof StubPropertySource)
175					&& !(source instanceof ConfigurationPropertySourcesPropertySource);
176		}
177	
178	}
