17	package org.springframework.boot.context.properties.source;
18	
19	import java.util.ArrayDeque;
20	import java.util.Deque;
21	import java.util.Iterator;
22	import java.util.Map;
23	import java.util.NoSuchElementException;
24	import java.util.function.Function;
25	
26	import org.jspecify.annotations.Nullable;
27	
28	import org.springframework.boot.env.PropertySourceInfo;
29	import org.springframework.core.env.ConfigurableEnvironment;
30	import org.springframework.core.env.MutablePropertySources;
31	import org.springframework.core.env.PropertySource;
32	import org.springframework.core.env.PropertySource.StubPropertySource;
33	import org.springframework.util.Assert;
34	import org.springframework.util.ConcurrentReferenceHashMap;
35	import org.springframework.util.ConcurrentReferenceHashMap.ReferenceType;
36	
37	/**
38	 * Adapter to convert Spring's {@link MutablePropertySources} to
39	 * {@link ConfigurationPropertySource ConfigurationPropertySources}.
40	 *
41	 * @author Phillip Webb
42	 */
43	class SpringConfigurationPropertySources implements Iterable<ConfigurationPropertySource> {
44	
45		private final Iterable<PropertySource<?>> sources;
46	
47		private final Map<PropertySource<?>, ConfigurationPropertySource> cache = new ConcurrentReferenceHashMap<>(16,
48				ReferenceType.SOFT);
49	
50		SpringConfigurationPropertySources(Iterable<PropertySource<?>> sources) {
51			Assert.notNull(sources, "'sources' must not be null");
52			this.sources = sources;
53		}
54	
55		boolean isUsingSources(Iterable<PropertySource<?>> sources) {
56			return this.sources == sources;
57		}
58	
59		@Override
60		public Iterator<ConfigurationPropertySource> iterator() {
61			return new SourcesIterator(this.sources.iterator(), this::adapt);
62		}
63	
64		private ConfigurationPropertySource adapt(PropertySource<?> source) {
65			ConfigurationPropertySource result = this.cache.get(source);
66			// Most PropertySources test equality only using the source name, so we need to
67			// check the actual source hasn't also changed.
68			if (result != null && result.getUnderlyingSource() == source) {
69				return result;
70			}
71			result = SpringConfigurationPropertySource.from(source);
72			if (source instanceof PropertySourceInfo propertySourceInfo) {
73				result = result.withPrefix(propertySourceInfo.getPrefix());
74			}
75			this.cache.put(source, result);
76			return result;
77		}
78	
79		private static class SourcesIterator implements Iterator<ConfigurationPropertySource> {
80	
81			private final Deque<Iterator<PropertySource<?>>> iterators;
82	
83			private @Nullable ConfigurationPropertySource next;
84	
85			private final Function<PropertySource<?>, ConfigurationPropertySource> adapter;
86	
87			SourcesIterator(Iterator<PropertySource<?>> iterator,
88					Function<PropertySource<?>, ConfigurationPropertySource> adapter) {
89				this.iterators = new ArrayDeque<>(4);
90				this.iterators.push(iterator);
91				this.adapter = adapter;
92			}
93	
94			@Override
95			public boolean hasNext() {
96				return fetchNext() != null;
97			}
98	
99			@Override
100			public ConfigurationPropertySource next() {
101				ConfigurationPropertySource next = fetchNext();
102				if (next == null) {
103					throw new NoSuchElementException();
104				}
105				this.next = null;
106				return next;
107			}
108	
109			private @Nullable ConfigurationPropertySource fetchNext() {
110				if (this.next == null) {
111					if (this.iterators.isEmpty()) {
112						return null;
113					}
114					if (!this.iterators.peek().hasNext()) {
115						this.iterators.pop();
116						return fetchNext();
117					}
118					PropertySource<?> candidate = this.iterators.peek().next();
119					if (candidate.getSource() instanceof ConfigurableEnvironment configurableEnvironment) {
120						push(configurableEnvironment);
121						return fetchNext();
122					}
123					if (isIgnored(candidate)) {
124						return fetchNext();
125					}
126					this.next = this.adapter.apply(candidate);
127				}
128				return this.next;
129			}
130	
131			private void push(ConfigurableEnvironment environment) {
132				this.iterators.push(environment.getPropertySources().iterator());
133			}
134	
135			private boolean isIgnored(PropertySource<?> candidate) {
136				return (candidate instanceof StubPropertySource
137						|| candidate instanceof ConfigurationPropertySourcesPropertySource);
138			}
139	
140		}
141	
142	}
