18	
19	import java.util.Locale;
20	import java.util.Map;
21	import java.util.Random;
22	
23	import org.jspecify.annotations.Nullable;
24	
25	import org.springframework.boot.context.properties.source.ConfigurationPropertyName.Form;
26	import org.springframework.boot.origin.Origin;
27	import org.springframework.boot.origin.PropertySourceOrigin;
28	import org.springframework.core.env.EnumerablePropertySource;
29	import org.springframework.core.env.PropertySource;
30	import org.springframework.core.env.StandardEnvironment;
31	import org.springframework.core.env.SystemEnvironmentPropertySource;
32	import org.springframework.util.Assert;
33	
34	/**
35	 * {@link ConfigurationPropertySource} backed by a non-enumerable Spring
36	 * {@link PropertySource} or a restricted {@link EnumerablePropertySource} implementation
37	 * (such as a security restricted {@code systemEnvironment} source). A
38	 * {@link PropertySource} is adapted with the help of a {@link PropertyMapper} which
39	 * provides the mapping rules for individual properties.
40	 * <p>
41	 * Each {@link ConfigurationPropertySource#getConfigurationProperty
42	 * getConfigurationProperty} call attempts to
43	 * {@link PropertyMapper#map(ConfigurationPropertyName) map} the
44	 * {@link ConfigurationPropertyName} to one or more {@code String} based names. This
45	 * allows fast property resolution for well-formed property sources.
46	 * <p>
47	 * When possible the {@link SpringIterableConfigurationPropertySource} will be used in
48	 * preference to this implementation since it supports full "relaxed" style resolution.
49	 *
50	 * @author Phillip Webb
51	 * @author Madhura Bhave
52	 * @see #from(PropertySource)
53	 * @see PropertyMapper
54	 * @see SpringIterableConfigurationPropertySource
55	 */
56	class SpringConfigurationPropertySource implements ConfigurationPropertySource {
57	
58		private static final PropertyMapper[] DEFAULT_MAPPERS = { DefaultPropertyMapper.INSTANCE };
59	
60		private static final PropertyMapper[] SYSTEM_ENVIRONMENT_MAPPERS = { SystemEnvironmentPropertyMapper.INSTANCE,
61				DefaultPropertyMapper.INSTANCE };
62	
63		private final PropertySource<?> propertySource;
64	
65		private final boolean systemEnvironmentSource;
66	
67		private final PropertyMapper[] mappers;
68	
69		/**
70		 * Create a new {@link SpringConfigurationPropertySource} implementation.
71		 * @param propertySource the source property source
72		 * @param systemEnvironmentSource if the source is from the system environment
73		 * @param mappers the property mappers
74		 */
75		SpringConfigurationPropertySource(PropertySource<?> propertySource, boolean systemEnvironmentSource,
76				PropertyMapper... mappers) {
77			Assert.notNull(propertySource, "'propertySource' must not be null");
78			Assert.isTrue(mappers.length > 0, "'mappers' must contain at least one item");
79			this.propertySource = propertySource;
80			this.systemEnvironmentSource = systemEnvironmentSource;
81			this.mappers = mappers;
82		}
83	
84		@Override
85		public @Nullable ConfigurationProperty getConfigurationProperty(@Nullable ConfigurationPropertyName name) {
86			if (name == null) {
87				return null;
88			}
89			for (PropertyMapper mapper : this.mappers) {
90				try {
91					for (String candidate : mapper.map(name)) {
92						Object value = getPropertySourceProperty(candidate);
93						if (value != null) {
94							Origin origin = PropertySourceOrigin.get(this.propertySource, candidate);
95							return ConfigurationProperty.of(this, name, value, origin);
96						}
97					}
98				}
99				catch (Exception ex) {
100					// Ignore
101				}
102			}
103			return null;
104		}
105	
106		protected final @Nullable Object getPropertySourceProperty(String name) {
107			// Save calls to SystemEnvironmentPropertySource.resolvePropertyName(...)
108			// since we've already done the mapping
109			PropertySource<?> propertySource = getPropertySource();
110			return (!this.systemEnvironmentSource) ? propertySource.getProperty(name)
111					: getSystemEnvironmentProperty(((SystemEnvironmentPropertySource) propertySource).getSource(), name);
112		}
113	
114		@Nullable Object getSystemEnvironmentProperty(Map<String, Object> systemEnvironment, String name) {
115			Object value = systemEnvironment.get(name);
116			return (value != null) ? value : systemEnvironment.get(name.toLowerCase(Locale.ROOT));
117		}
118	
119		@Override
120		public ConfigurationPropertyState containsDescendantOf(ConfigurationPropertyName name) {
121			PropertySource<?> source = getPropertySource();
122			Object underlyingSource = source.getSource();
123			if (underlyingSource instanceof Random) {
124				return containsDescendantOfForRandom("random", name);
125			}
126			if (underlyingSource instanceof PropertySource<?> underlyingPropertySource
127					&& underlyingPropertySource.getSource() instanceof Random) {
128				// Assume wrapped random sources use the source name as the prefix
129				return containsDescendantOfForRandom(source.getName(), name);
130			}
131			return ConfigurationPropertyState.UNKNOWN;
132		}
133	
134		private static ConfigurationPropertyState containsDescendantOfForRandom(String prefix,
135				ConfigurationPropertyName name) {
136			if (name.getNumberOfElements() > 1 && name.getElement(0, Form.DASHED).equals(prefix)) {
137				return ConfigurationPropertyState.PRESENT;
138			}
139			return ConfigurationPropertyState.ABSENT;
140		}
141	
142		@Override
143		public Object getUnderlyingSource() {
144			return this.propertySource;
145		}
146	
147		protected PropertySource<?> getPropertySource() {
148			return this.propertySource;
149		}
150	
151		protected final boolean isSystemEnvironmentSource() {
152			return this.systemEnvironmentSource;
153		}
154	
155		protected final PropertyMapper[] getMappers() {
156			return this.mappers;
157		}
158	
159		@Override
160		public String toString() {
161			return this.propertySource.toString();
162		}
163	
164		/**
165		 * Create a new {@link SpringConfigurationPropertySource} for the specified
166		 * {@link PropertySource}.
167		 * @param source the source Spring {@link PropertySource}
168		 * @return a {@link SpringConfigurationPropertySource} or
169		 * {@link SpringIterableConfigurationPropertySource} instance
170		 */
171		static SpringConfigurationPropertySource from(PropertySource<?> source) {
172			Assert.notNull(source, "'source' must not be null");
173			boolean systemEnvironmentSource = isSystemEnvironmentPropertySource(source);
174			PropertyMapper[] mappers = (!systemEnvironmentSource) ? DEFAULT_MAPPERS : SYSTEM_ENVIRONMENT_MAPPERS;
175			return (!isFullEnumerable(source))
176					? new SpringConfigurationPropertySource(source, systemEnvironmentSource, mappers)
177					: new SpringIterableConfigurationPropertySource((EnumerablePropertySource<?>) source,
178							systemEnvironmentSource, mappers);
179		}
180	
181		private static boolean isSystemEnvironmentPropertySource(PropertySource<?> source) {
182			String name = source.getName();
183			return (source instanceof SystemEnvironmentPropertySource)
184					&& (StandardEnvironment.SYSTEM_ENVIRONMENT_PROPERTY_SOURCE_NAME.equals(name)
185							|| name.endsWith("-" + StandardEnvironment.SYSTEM_ENVIRONMENT_PROPERTY_SOURCE_NAME));
186		}
187	
188		private static boolean isFullEnumerable(PropertySource<?> source) {
189			PropertySource<?> rootSource = getRootSource(source);
190			if (rootSource.getSource() instanceof Map<?, ?> map) {
191				// Check we're not security restricted
192				try {
193					map.size();
194				}
195				catch (UnsupportedOperationException ex) {
196					return false;
197				}
198			}
199			return (source instanceof EnumerablePropertySource);
200		}
201	
202		private static PropertySource<?> getRootSource(PropertySource<?> source) {
203			while (source.getSource() instanceof PropertySource<?> propertySource) {
204				source = propertySource;
205			}
206			return source;
207		}
208	
209	}
