18	
19	import java.util.NoSuchElementException;
20	import java.util.function.Consumer;
21	import java.util.function.Function;
22	import java.util.function.Supplier;
23	
24	import org.jspecify.annotations.Nullable;
25	
26	import org.springframework.lang.Contract;
27	import org.springframework.util.Assert;
28	import org.springframework.util.ObjectUtils;
29	
30	/**
31	 * A container object to return the result of a {@link Binder} bind operation. May contain
32	 * either a successfully bound object or an empty result.
33	 *
34	 * @param <T> the result type
35	 * @author Phillip Webb
36	 * @author Madhura Bhave
37	 * @since 2.0.0
38	 */
39	public final class BindResult<T> {
40	
41		private static final BindResult<?> UNBOUND = new BindResult<>(null);
42	
43		private final @Nullable T value;
44	
45		private BindResult(@Nullable T value) {
46			this.value = value;
47		}
48	
49		/**
50		 * Return the object that was bound or throw a {@link NoSuchElementException} if no
51		 * value was bound.
52		 * @return the bound value (never {@code null})
53		 * @throws NoSuchElementException if no value was bound
54		 * @see #isBound()
55		 */
56		public T get() throws NoSuchElementException {
57			if (this.value == null) {
58				throw new NoSuchElementException("No value bound");
59			}
60			return this.value;
61		}
62	
63		/**
64		 * Returns {@code true} if a result was bound.
65		 * @return if a result was bound
66		 */
67		public boolean isBound() {
68			return (this.value != null);
69		}
70	
71		/**
72		 * Invoke the specified consumer with the bound value, or do nothing if no value has
73		 * been bound.
74		 * @param consumer block to execute if a value has been bound
75		 */
76		public void ifBound(Consumer<? super T> consumer) {
77			Assert.notNull(consumer, "'consumer' must not be null");
78			if (this.value != null) {
79				consumer.accept(this.value);
80			}
81		}
82	
83		/**
84		 * Apply the provided mapping function to the bound value, or return an updated
85		 * unbound result if no value has been bound.
86		 * @param <U> the type of the result of the mapping function
87		 * @param mapper a mapping function to apply to the bound value. The mapper will not
88		 * be invoked if no value has been bound.
89		 * @return an {@code BindResult} describing the result of applying a mapping function
90		 * to the value of this {@code BindResult}.
91		 */
92		public <U> BindResult<U> map(Function<? super T, ? extends U> mapper) {
93			Assert.notNull(mapper, "'mapper' must not be null");
94			return of((this.value != null) ? mapper.apply(this.value) : null);
95		}
96	
97		/**
98		 * Return the object that was bound, or {@code other} if no value has been bound.
99		 * @param other the value to be returned if there is no bound value (may be
100		 * {@code null})
101		 * @return the value, if bound, otherwise {@code other}
102		 */
103		@Contract("!null -> !null")
104		public @Nullable T orElse(@Nullable T other) {
105			return (this.value != null) ? this.value : other;
106		}
107	
108		/**
109		 * Return the object that was bound, or the result of invoking {@code other} if no
110		 * value has been bound.
111		 * @param other a {@link Supplier} of the value to be returned if there is no bound
112		 * value
113		 * @return the value, if bound, otherwise the supplied {@code other}
114		 */
115		public T orElseGet(Supplier<? extends T> other) {
116			return (this.value != null) ? this.value : other.get();
117		}
118	
119		/**
120		 * Return the object that was bound, or throw an exception to be created by the
121		 * provided supplier if no value has been bound.
122		 * @param <X> the type of the exception to be thrown
123		 * @param exceptionSupplier the supplier which will return the exception to be thrown
124		 * @return the present value
125		 * @throws X if there is no value present
126		 */
127		public <X extends Throwable> T orElseThrow(Supplier<? extends X> exceptionSupplier) throws X {
128			if (this.value == null) {
129				throw exceptionSupplier.get();
130			}
131			return this.value;
132		}
133	
134		@Override
135		public boolean equals(Object obj) {
136			if (this == obj) {
137				return true;
138			}
139			if (obj == null || getClass() != obj.getClass()) {
140				return false;
141			}
142			return ObjectUtils.nullSafeEquals(this.value, ((BindResult<?>) obj).value);
143		}
144	
145		@Override
146		public int hashCode() {
147			return ObjectUtils.nullSafeHashCode(this.value);
148		}
149	
150		@SuppressWarnings("unchecked")
151		static <T> BindResult<T> of(@Nullable T value) {
152			if (value == null) {
153				return (BindResult<T>) UNBOUND;
154			}
155			return new BindResult<>(value);
156		}
157	
158	}
