28	/**
29	 * {@link PropertyMapper} for system environment variables. Names are mapped by removing
30	 * invalid characters, converting to lower case and replacing "{@code _}" with
31	 * "{@code .}". For example, "{@code SERVER_PORT}" is mapped to "{@code server.port}". In
32	 * addition, numeric elements are mapped to indexes (e.g. "{@code HOST_0}" is mapped to
33	 * "{@code host[0]}").
34	 *
35	 * @author Phillip Webb
36	 * @author Madhura Bhave
37	 * @see PropertyMapper
38	 * @see SpringConfigurationPropertySource
39	 */
40	final class SystemEnvironmentPropertyMapper implements PropertyMapper {
41	
42		public static final PropertyMapper INSTANCE = new SystemEnvironmentPropertyMapper();
43	
44		private final Map<String, ConfigurationPropertyName> propertySourceNameCache = new ConcurrentReferenceHashMap<>();
45	
46		@Override
47		public List<String> map(ConfigurationPropertyName configurationPropertyName) {
48			List<String> mapped = new ArrayList<>(4);
49			addIfMissing(mapped, configurationPropertyName.toString(ToStringFormat.SYSTEM_ENVIRONMENT, true));
50			addIfMissing(mapped, configurationPropertyName.toString(ToStringFormat.LEGACY_SYSTEM_ENVIRONMENT, true));
51			addIfMissing(mapped, configurationPropertyName.toString(ToStringFormat.SYSTEM_ENVIRONMENT, false));
52			addIfMissing(mapped, configurationPropertyName.toString(ToStringFormat.LEGACY_SYSTEM_ENVIRONMENT, false));
53			return mapped;
54		}
55	
56		private void addIfMissing(List<String> list, String value) {
57			if (!list.contains(value)) {
58				list.add(value);
59			}
60		}
61	
62		@Override
63		public ConfigurationPropertyName map(String propertySourceName) {
64			ConfigurationPropertyName configurationPropertyName = this.propertySourceNameCache.get(propertySourceName);
65			if (configurationPropertyName == null) {
66				configurationPropertyName = convertName(propertySourceName);
67				this.propertySourceNameCache.put(propertySourceName, configurationPropertyName);
68			}
69			return configurationPropertyName;
70		}
71	
72		private ConfigurationPropertyName convertName(String propertySourceName) {
73			try {
74				return ConfigurationPropertyName.adapt(propertySourceName, '_', this::processElementValue);
75			}
76			catch (Exception ex) {
77				return ConfigurationPropertyName.EMPTY;
78			}
79		}
80	
81		private CharSequence processElementValue(CharSequence value) {
82			String result = value.toString().toLowerCase(Locale.ENGLISH);
83			return isNumber(result) ? "[" + result + "]" : result;
84		}
85	
86		private static boolean isNumber(String string) {
87			return string.chars().allMatch(Character::isDigit);
88		}
